    const _get = (data, x, y, z) => get(data, x % xn, y % yn, z % zn);
    const _set = (data, x, y, z, d) => set(data, x % xn, y % yn, z % zn, d);
    const _add = (data, x, y, z, d) => add(data, x % xn, y % yn, z % zn, d);
    const _dataOffset = (x, y, z) => dataOffset(x % xn, y % yn, z % zn);
    const _space = {
        ...space,
        dimensions: _dimensions,
        get: _get,
        set: _set,
        add: _add,
        dataOffset: _dataOffset,
    };
